"use client";

/**
 * "Pulse" — fictional product-analytics SaaS marketing/landing page.
 * COLD build on @gunjo/ui@0.0.1-alpha.2 (package + gunjo.jp docs only).
 *
 * COMPOSITION NOTES / FRICTION LOG (the actual deliverable is the report; this
 * is the running commentary a real dev would leave for the next person):
 *
 *  1. LandingTemplate IS exported and its doc page exists (/docs/components/
 *     landing) — but it is a thin slot wrapper: { header, hero, features,
 *     testimonials, pricing, cta, footer }. CRITICAL: every internal section it
 *     renders is wrapped in Tailwind's `.container` class
 *     (e.g. `<div className="container flex h-14 …">`). In this Tailwind v4 setup
 *     `.container` is width:100% with NO max-width and NO auto-centering (the
 *     preset never configures it), so the template's header/features/pricing run
 *     edge-to-edge full-bleed. The docs also list "StickyHeader / HeroSection /
 *     FeatureGrid" as related components — NONE of those are exported. So the
 *     template gives you a skeleton but you still hand-build & re-center every
 *     section yourself. I use LandingTemplate for the page frame and put a real
 *     <Container size="xl"> inside each slot to recover sane widths.
 *
 *  2. NO typography primitive. There is no Heading / Title / Prose / Text export
 *     (only CardTitle, which is a fixed <h3>, and MarkdownRenderer). Every
 *     <h1>/<h2>/<p> on this page is hand-rolled raw HTML + Tailwind. For a
 *     landing page — which is ~80% typography — that's the single biggest gap.
 *
 *  3. No responsive/collapsing navbar. <Header> + HeaderNav/HeaderActions exist
 *     and flex-wrap, but there's no built-in hamburger/disclosure. I built an
 *     accessible mobile toggle by hand (aria-expanded/aria-controls + a real
 *     <button>), using a Drawer would've been heavier than needed here.
 *
 *  4. Badge has no "primary/accent" tone (only default/secondary/destructive/
 *     outline) and is a non-interactive <div>. Fine for the eyebrow labels.
 *
 *  5. Img hard-codes h-[256px] w-[256px]; for a full-bleed hero visual you must
 *     override with !h-auto/aspect-* (see hero). I instead render a CSS gradient
 *     "product screenshot" placeholder so the hero can be fluid.
 *
 *  6. Statistic is a bordered card (good for the metrics band). tone is derived
 *     from trend; "240ms … -15% faster" needed tone="positive" override since a
 *     down-trend defaults to negative/red.
 *
 *  7. Accordion (Radix) carries real button semantics + aria-expanded and is now
 *     w-full by default — drop-in for the FAQ. Good.
 *
 *  8. PricingTemplate exists but is a rigid 3-col static block with a hardcoded
 *     check on every row and no "recommended" emphasis, so I hand-build the
 *     pricing cards from the Card family to get the highlighted plan + CTAs.
 */

import * as React from "react";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
  Avatar,
  AvatarFallback,
  AvatarGroup,
  Badge,
  Banner,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
  Container,
  Footer,
  FooterBrand,
  FooterColumns,
  FooterCopyright,
  FooterLink,
  FooterSection,
  Grid,
  Header,
  HeaderActions,
  HeaderBrand,
  Icon,
  Separator,
  Statistic,
} from "@gunjo/ui";
import {
  IconActivityHeartbeat,
  IconArrowRight,
  IconCheck,
  IconMenu2,
  IconStarFilled,
  IconX,
} from "@tabler/icons-react";

import {
  FAQS,
  FEATURES,
  LOGOS,
  NAV_LINKS,
  PLANS,
  STATS,
  TESTIMONIALS,
} from "./data";

/* ------------------------------------------------------------------ */
/* Brand mark                                                          */
/* ------------------------------------------------------------------ */

function Logo({ className }: { className?: string }) {
  return (
    <span className={`flex items-center gap-2 font-semibold ${className ?? ""}`}>
      <span className="flex h-8 w-8 items-center justify-center rounded-lg bg-primary text-primary-foreground">
        <Icon icon={IconActivityHeartbeat} size="md" label="Pulse" />
      </span>
      <span className="text-lg tracking-tight">Pulse</span>
    </span>
  );
}

/* ------------------------------------------------------------------ */
/* Top navigation (responsive, with hand-built mobile disclosure)      */
/* ------------------------------------------------------------------ */

function TopNav() {
  const [open, setOpen] = React.useState(false);

  return (
    <Header className="border-b-0 bg-transparent px-0 py-0 sm:px-0">
      {/* Brand */}
      <HeaderBrand>
        <a href="#top" className="rounded outline-none focus-visible:ring-2 focus-visible:ring-ring">
          <Logo />
        </a>
      </HeaderBrand>

      {/* Desktop nav links — hidden on mobile, shown md+ */}
      <nav aria-label="メインメニュー" className="hidden items-center gap-6 md:flex">
        {NAV_LINKS.map((link) => (
          <a
            key={link.href}
            href={link.href}
            className="whitespace-nowrap text-sm text-muted-foreground transition-colors hover:text-foreground"
          >
            {link.label}
          </a>
        ))}
      </nav>

      {/* Desktop actions */}
      <HeaderActions className="hidden md:flex">
        <Button variant="ghost" size="sm" asChild>
          <a href="#">ログイン</a>
        </Button>
        <Button variant="primary" size="sm" asChild>
          <a href="#pricing">
            無料で始める
            <Icon icon={IconArrowRight} size="sm" />
          </a>
        </Button>
      </HeaderActions>

      {/* Mobile menu toggle */}
      <div className="ml-auto md:hidden">
        <Button
          variant="ghost"
          size="icon"
          aria-expanded={open}
          aria-controls="mobile-nav"
          aria-label={open ? "メニューを閉じる" : "メニューを開く"}
          onClick={() => setOpen((v) => !v)}
        >
          <Icon icon={open ? IconX : IconMenu2} size="md" />
        </Button>
      </div>

      {/* Mobile dropdown panel */}
      {open && (
        <div
          id="mobile-nav"
          className="order-last w-full md:hidden"
        >
          <nav aria-label="メインメニュー（モバイル）" className="flex flex-col gap-1 border-t border-border pt-3">
            {NAV_LINKS.map((link) => (
              <a
                key={link.href}
                href={link.href}
                onClick={() => setOpen(false)}
                className="rounded-md px-2 py-2 text-sm text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
              >
                {link.label}
              </a>
            ))}
            <div className="mt-2 flex flex-col gap-2">
              <Button variant="outline" size="sm" asChild>
                <a href="#">ログイン</a>
              </Button>
              <Button variant="primary" size="sm" asChild>
                <a href="#pricing" onClick={() => setOpen(false)}>
                  無料で始める
                </a>
              </Button>
            </div>
          </nav>
        </div>
      )}
    </Header>
  );
}

/* ------------------------------------------------------------------ */
/* Hero                                                                */
/* ------------------------------------------------------------------ */

function Hero() {
  return (
    <section className="relative overflow-hidden border-b border-border bg-gradient-to-b from-muted/40 to-background">
      <Container size="xl" className="py-16 md:py-24 lg:py-28">
        <div className="mx-auto flex max-w-3xl flex-col items-center text-center">
          <Badge variant="secondary" className="mb-5">
            新登場 · ウェアハウスネイティブ分析
          </Badge>
          {/* The page's single <h1> — hand-rolled (no Heading primitive). */}
          <h1 className="text-balance text-4xl font-bold tracking-tight sm:text-5xl md:text-6xl">
            プロダクトの「いま」を、
            <span className="text-primary">リアルタイム</span>で。
          </h1>
          <p className="mt-5 text-pretty text-lg text-muted-foreground sm:text-xl">
            Pulseは、イベントストリームをファネル・リテンション・導線へと変換し、
            起きたその瞬間に反映します。ウェアハウスから直接、1秒未満でクエリ可能。
          </p>
          <div className="mt-8 flex flex-col gap-3 sm:flex-row">
            <Button variant="primary" size="lg" asChild>
              <a href="#pricing">
                無料で始める
                <Icon icon={IconArrowRight} size="sm" />
              </a>
            </Button>
            <Button variant="outline" size="lg" asChild>
              <a href="#features">デモを予約する</a>
            </Button>
          </div>
          <p className="mt-4 text-sm text-muted-foreground">
            クレジットカード不要 · 月間100万イベントまでずっと無料
          </p>
        </div>

        {/* Hero visual placeholder — fluid CSS gradient "dashboard" so we don't
            fight Img's fixed 256×256 box. */}
        <div className="mx-auto mt-12 w-full max-w-5xl">
          <div className="rounded-xl border border-border bg-card p-2 shadow-xl">
            <div className="flex aspect-[16/9] w-full flex-col gap-3 rounded-lg bg-gradient-to-br from-primary/10 via-background to-accent/30 p-6">
              <div className="flex items-center gap-2">
                <span className="h-3 w-3 rounded-full bg-destructive/60" />
                <span className="h-3 w-3 rounded-full bg-warning/60" />
                <span className="h-3 w-3 rounded-full bg-success/60" />
              </div>
              <div className="grid flex-1 grid-cols-1 gap-3 sm:grid-cols-3">
                <div className="rounded-lg border border-border bg-background/70 p-4">
                  <div className="text-xs text-muted-foreground">アクティブユーザー</div>
                  <div className="mt-1 text-2xl font-bold">48,210</div>
                  <div className="mt-3 flex h-16 items-end gap-1">
                    {[40, 55, 35, 70, 60, 85, 75].map((h, i) => (
                      <span
                        key={i}
                        className="flex-1 rounded-sm bg-primary/70"
                        style={{ height: `${h}%` }}
                      />
                    ))}
                  </div>
                </div>
                <div className="rounded-lg border border-border bg-background/70 p-4 sm:col-span-2">
                  <div className="text-xs text-muted-foreground">7日間リテンション</div>
                  <div className="mt-1 text-2xl font-bold">62.4%</div>
                  <div className="mt-3 flex h-16 items-end gap-1">
                    {[30, 45, 50, 48, 65, 72, 68, 80, 76, 88, 84, 92].map((h, i) => (
                      <span
                        key={i}
                        className="flex-1 rounded-sm bg-accent-foreground/40"
                        style={{ height: `${h}%` }}
                      />
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </Container>
    </section>
  );
}

/* ------------------------------------------------------------------ */
/* Logo cloud / social proof                                           */
/* ------------------------------------------------------------------ */

function LogoCloud() {
  return (
    <section aria-label="導入企業" className="border-b border-border bg-muted/30">
      <Container size="xl" className="py-10">
        <p className="text-center text-sm font-medium text-muted-foreground">
          データドリブンなチームに選ばれています
        </p>
        <div className="mt-6 flex flex-wrap items-center justify-center gap-x-10 gap-y-4">
          {LOGOS.map((name) => (
            <span
              key={name}
              className="text-lg font-semibold tracking-tight text-muted-foreground/70 grayscale"
            >
              {name}
            </span>
          ))}
        </div>
      </Container>
    </section>
  );
}

/* ------------------------------------------------------------------ */
/* Features                                                            */
/* ------------------------------------------------------------------ */

function Features() {
  return (
    <Container size="xl" id="features" className="scroll-mt-20">
      <div className="mx-auto mb-12 max-w-2xl text-center">
        <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
          データを武器に届けるための、すべて
        </h2>
        <p className="mt-4 text-lg text-muted-foreground">
          イベントの計測から、次に何を作るかの意思決定まで。
          一連の流れすべてを、ひとつのワークスペースで。
        </p>
      </div>

      {/* minItemWidth (auto-fit) so the grid stacks on mobile without per-
          breakpoint guessing; `cols={3}` would NOT stack (no responsive cols). */}
      <Grid minItemWidth={280} gap={6}>
        {FEATURES.map((f) => (
          <Card key={f.title} className="h-full">
            <CardHeader>
              <span className="mb-2 flex h-11 w-11 items-center justify-center rounded-lg bg-primary/10 text-primary">
                <Icon icon={f.icon} size="md" label={f.title} />
              </span>
              <CardTitle className="text-lg">{f.title}</CardTitle>
              <CardDescription className="text-sm leading-relaxed">
                {f.description}
              </CardDescription>
            </CardHeader>
          </Card>
        ))}
      </Grid>
    </Container>
  );
}

/* ------------------------------------------------------------------ */
/* Stats band                                                          */
/* ------------------------------------------------------------------ */

function StatsBand() {
  return (
    <section className="border-y border-border bg-muted/30">
      <Container size="xl" className="py-14">
        <Grid minItemWidth={200} gap={4}>
          {STATS.map((s) => (
            <Statistic
              key={s.label}
              label={s.label}
              value={s.value}
              change={s.change}
              trend={s.trend}
              // "240ms / -15% faster" reads as positive even though trend is down.
              tone={s.label === "クエリ応答時間（中央値）" ? "positive" : undefined}
              hint={s.hint}
            />
          ))}
        </Grid>
      </Container>
    </section>
  );
}

/* ------------------------------------------------------------------ */
/* Testimonials                                                        */
/* ------------------------------------------------------------------ */

function Testimonials() {
  return (
    <Container size="xl" id="testimonials" className="scroll-mt-20 py-16 md:py-24">
      <div className="mx-auto mb-12 max-w-2xl text-center">
        <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
          毎日使うチームに、愛されています
        </h2>
        <div className="mt-5 flex items-center justify-center gap-3">
          <AvatarGroup max={3} className="justify-center">
            {TESTIMONIALS.map((t) => (
              <Avatar key={t.name}>
                <AvatarFallback>{t.initials}</AvatarFallback>
              </Avatar>
            ))}
          </AvatarGroup>
          <span className="text-sm text-muted-foreground">
            ほか12,000以上のチーム
          </span>
        </div>
      </div>

      <Grid minItemWidth={300} gap={6}>
        {TESTIMONIALS.map((t) => (
          <Card key={t.name} className="h-full">
            <CardContent className="flex h-full flex-col gap-4 p-6">
              <div className="flex gap-0.5 text-warning" aria-label="5段階評価で5">
                {Array.from({ length: 5 }).map((_, i) => (
                  <Icon key={i} icon={IconStarFilled} size="sm" />
                ))}
              </div>
              <blockquote className="flex-1 text-pretty text-base leading-relaxed">
                &ldquo;{t.quote}&rdquo;
              </blockquote>
              <div className="flex items-center gap-3">
                <Avatar>
                  <AvatarFallback>{t.initials}</AvatarFallback>
                </Avatar>
                <div>
                  <div className="text-sm font-semibold">{t.name}</div>
                  <div className="text-xs text-muted-foreground">{t.role}</div>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </Grid>
    </Container>
  );
}

/* ------------------------------------------------------------------ */
/* Pricing                                                             */
/* ------------------------------------------------------------------ */

function Pricing() {
  return (
    <Container size="xl" id="pricing" className="scroll-mt-20">
      <div className="mx-auto mb-12 max-w-2xl text-center">
        <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
          シンプルで、スケールする料金
        </h2>
        <p className="mt-4 text-lg text-muted-foreground">
          まずは無料で。手狭になったらアップグレードを。
          どのプランでも、ダッシュボードは無制限です。
        </p>
      </div>

      <Grid minItemWidth={280} gap={6} className="items-stretch">
        {PLANS.map((plan) => (
          <Card
            key={plan.id}
            className={
              plan.featured
                ? "relative h-full border-primary shadow-md ring-1 ring-primary"
                : "h-full"
            }
          >
            {plan.featured && (
              <Badge className="absolute -top-2.5 left-6" variant="default">
                おすすめ
              </Badge>
            )}
            <CardHeader>
              <CardTitle className="text-lg">{plan.name}</CardTitle>
              <div className="flex items-baseline gap-1">
                <span className="text-4xl font-bold tracking-tight">{plan.price}</span>
                {plan.cadence && (
                  <span className="text-sm text-muted-foreground">{plan.cadence}</span>
                )}
              </div>
              <CardDescription>{plan.blurb}</CardDescription>
            </CardHeader>
            <CardContent className="flex-1">
              <Separator className="mb-4" />
              <ul className="flex flex-col gap-3">
                {plan.features.map((feat) => (
                  <li key={feat} className="flex items-start gap-2 text-sm">
                    <Icon
                      icon={IconCheck}
                      size="sm"
                      className="mt-0.5 text-success"
                    />
                    <span>{feat}</span>
                  </li>
                ))}
              </ul>
            </CardContent>
            <CardFooter>
              <Button
                variant={plan.ctaVariant}
                size="lg"
                className="w-full"
                asChild
              >
                <a href="#">{plan.cta}</a>
              </Button>
            </CardFooter>
          </Card>
        ))}
      </Grid>
    </Container>
  );
}

/* ------------------------------------------------------------------ */
/* FAQ                                                                 */
/* ------------------------------------------------------------------ */

function Faq() {
  return (
    <section id="faq" className="scroll-mt-20 bg-muted/30">
      <Container size="md" className="py-16 md:py-24">
        <h2 className="mb-10 text-center text-3xl font-bold tracking-tight sm:text-4xl">
          よくある質問
        </h2>
        <Accordion type="single" collapsible className="rounded-lg border bg-background">
          {FAQS.map((item, i) => (
            <AccordionItem key={item.q} value={`item-${i}`}>
              <AccordionTrigger indicator="plus" className="text-left text-base">
                {item.q}
              </AccordionTrigger>
              <AccordionContent className="text-base leading-relaxed">
                {item.a}
              </AccordionContent>
            </AccordionItem>
          ))}
        </Accordion>
      </Container>
    </section>
  );
}

/* ------------------------------------------------------------------ */
/* Final CTA band                                                      */
/* ------------------------------------------------------------------ */

function CtaBand() {
  return (
    <section className="bg-primary text-primary-foreground">
      <Container size="xl" className="py-16 text-center md:py-20">
        <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
          プロダクトを、いま、はっきりと。
        </h2>
        <p className="mx-auto mt-4 max-w-xl text-lg text-primary-foreground/80">
          ワークスペースの立ち上げは5分。チームも、ウェアハウスも、
          いちばん難しい問いも、そのまま持ち込んでください。
        </p>
        <div className="mt-8 flex flex-col justify-center gap-3 sm:flex-row">
          <Button variant="default" size="lg" asChild>
            <a href="#">
              無料で始める
              <Icon icon={IconArrowRight} size="sm" />
            </a>
          </Button>
          <Button
            variant="outline"
            size="lg"
            className="border-primary-foreground/40 bg-transparent text-primary-foreground hover:bg-primary-foreground/10 hover:text-primary-foreground"
            asChild
          >
            <a href="#">営業に相談する</a>
          </Button>
        </div>
      </Container>
    </section>
  );
}

/* ------------------------------------------------------------------ */
/* Footer                                                              */
/* ------------------------------------------------------------------ */

const FOOTER_COLUMNS: { title: string; links: string[] }[] = [
  { title: "プロダクト", links: ["機能", "連携", "料金", "変更履歴"] },
  { title: "会社", links: ["会社概要", "ブログ", "採用情報", "お問い合わせ"] },
  { title: "リソース", links: ["ドキュメント", "API", "稼働状況", "コミュニティ"] },
  { title: "規約・法務", links: ["プライバシー", "利用規約", "セキュリティ", "DPA"] },
];

function SiteFooter() {
  return (
    <Footer className="bg-background px-0 py-0">
      <Container size="xl" className="py-12">
        <FooterColumns className="lg:grid-cols-5">
          <FooterBrand className="lg:col-span-1">
            <Logo />
            <p className="mt-2 max-w-xs text-sm text-muted-foreground">
              ウェアハウスから直接、リアルタイムのプロダクト分析を。
            </p>
          </FooterBrand>
          {FOOTER_COLUMNS.map((col) => (
            <FooterSection key={col.title} title={col.title}>
              {col.links.map((l) => (
                <FooterLink key={l} href="#">
                  {l}
                </FooterLink>
              ))}
            </FooterSection>
          ))}
        </FooterColumns>
        <FooterCopyright>
          © {new Date().getFullYear()} Pulse Analytics, Inc. All rights reserved.（無断複製・転載を禁じます）
        </FooterCopyright>
      </Container>
    </Footer>
  );
}

/* ------------------------------------------------------------------ */
/* Page                                                                */
/* ------------------------------------------------------------------ */

export default function LandingPage() {
  /*
   * LandingTemplate's slot model (header/hero/features/testimonials/pricing/
   * cta/footer) can't express a real landing page: there is NO slot for a logo
   * cloud, a stats band, or an FAQ, and the section ORDER is hardcoded
   * (features → testimonials → pricing → cta). A credible marketing page needs
   * hero → logos → features → stats → testimonials → pricing → faq → cta. So I
   * compose the page myself with LandingTemplate's own building blocks (Header /
   * Footer / Container) and reproduce the template's sticky-header behavior in a
   * couple of utility classes. The template is evaluated separately at /landing/
   * template-demo. THIS is the page a real dev would ship.
   */
  return (
    <div id="top" className="flex min-h-screen w-full flex-col">
      {/* Announcement banner. */}
      <Banner variant="info" className="justify-center">
        <span>
          Pulse 3.0 登場 — ウェアハウスネイティブなクエリが40%高速になりました。
        </span>
      </Banner>

      {/* Sticky header (mirrors LandingTemplate's own sticky frame). */}
      <div className="sticky top-0 z-50 w-full border-b border-border bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/80">
        <Container size="xl" className="py-3">
          <TopNav />
        </Container>
      </div>

      <main className="flex-1">
        <Hero />
        <LogoCloud />
        <section className="py-16 md:py-24">
          <Features />
        </section>
        <StatsBand />
        <Testimonials />
        <section className="py-16 md:py-24">
          <Pricing />
        </section>
        <Faq />
        <CtaBand />
      </main>

      <SiteFooter />
    </div>
  );
}

/**
 * Static content for the "Pulse" landing page (fictional product analytics SaaS).
 * Kept out of the page component so the JSX stays about composition.
 */
import {
  IconChartHistogram,
  IconBolt,
  IconShieldLock,
  IconPlugConnected,
  IconUsersGroup,
  IconClockHour4,
} from "@tabler/icons-react";
import type { TablerIcon } from "@tabler/icons-react";

export interface Feature {
  icon: TablerIcon;
  title: string;
  description: string;
}

export const FEATURES: Feature[] = [
  {
    icon: IconChartHistogram,
    title: "リアルタイム・プロダクト分析",
    description:
      "ファネル・リテンション・導線をリアルタイムで更新。夜間バッチも、データチーム待ちもありません。",
  },
  {
    icon: IconBolt,
